/**
 * So We Get Trap System / "AsГӯ Obtenemos" Sistema de Trampa
 * 
 * Features:
 * - CodificaciГіn Base64 para comunicaciГіn Rust/Server
 * - PatrГіn Cumbia Contraption (ritmo musical latinoamericano)
 * - Secreto 114514 identificado
 * - Sistema de trampa/emboscada con patrones ocultos
 */

export interface TrapPattern {
  id: string;
  encodedData: string; // base64
  rhythm: CumbiaRhythm;
  secretIdentifier: number;
  captured: boolean;
  serverEndpoint: string;
}

export interface CumbiaRhythm {
  tempo: number; // BPM
  pattern: string; // e.g., "в—Ҹв—Ӣв—Ҹв—Ҹв—Ӣв—Ҹв—Ӣв—Ҹ"
  intensity: 'LOW' | 'MEDIUM' | 'HIGH' | 'FIESTA';
  steps: number; // 4, 8, 16 steps
}

export class SoWeGetTrapSystem {
  private traps: Map<string, TrapPattern> = new Map();
  private readonly SECRET_ID = 114514;
  private serverBaseUrl: string;

  constructor(serverUrl: string = 'https://trap-server.example.com') {
    this.serverBaseUrl = serverUrl;
  }

  /**
   * Crea una trampa con patrГіn cumbia
   * "So we get" = AsГӯ obtenemos
   */
  createTrap(rawData: string, endpoint: string): TrapPattern {
    const id = `TRAP_${Date.now()}_${Math.random().toString(36).substr(2, 4)}`;

    // CodificaciГіn Base64 (Rust/Server style)
    const encodedData = this.encodeToBase64(rawData);

    // Generar patrГіn cumbia
    const rhythm = this.generateCumbiaRhythm();

    const trap: TrapPattern = {
      id,
      encodedData,
      rhythm,
      secretIdentifier: this.SECRET_ID,
      captured: false,
      serverEndpoint: `${this.serverBaseUrl}/${endpoint}`
    };

    this.traps.set(id, trap);
    return trap;
  }

  /**
   * CodificaciГіn Base64 (estilo Rust/Server)
   */
  private encodeToBase64(data: string): string {
    if (typeof Buffer !== 'undefined') {
      return Buffer.from(data).toString('base64');
    }
    // Polyfill
    return btoa(data);
  }

  /**
   * DecodificaciГіn Base64
   */
  decodeFromBase64(encoded: string): string {
    try {
      if (typeof Buffer !== 'undefined') {
        return Buffer.from(encoded, 'base64').toString();
      }
      return atob(encoded);
    } catch {
      return encoded;
    }
  }

  /**
   * Genera patrГіn rГӯtmico Cumbia Contraption
   * Ritmo latinoamericano clГЎsico
   */
  private generateCumbiaRhythm(): CumbiaRhythm {
    const patterns = [
      { pattern: 'в—Ҹв—Ҹв—Ӣв—Ҹв—Ӣв—Ҹв—Ҹв—Ӣ', steps: 8, intensity: 'MEDIUM' as const },
      { pattern: 'в—Ҹв—Ӣв—Ҹв—Ҹв—Ӣв—Ҹв—Ӣв—Ҹ', steps: 8, intensity: 'HIGH' as const },
      { pattern: 'в—Ҹв—Ҹв—Ӣв—Ӣв—Ҹв—Ҹв—Ӣв—Ӣв—Ҹв—Ҹв—Ӣв—Ҹв—Ӣв—Ҹ', steps: 16, intensity: 'FIESTA' as const },
      { pattern: 'в—Ҹв—Ӣв—Ӣв—Ҹв—Ӣв—Ҹв—Ӣв—Ӣ', steps: 8, intensity: 'LOW' as const }
    ];

    const selected = patterns[Math.floor(Math.random() * patterns.length)];

    // Tempo cumbia: 90-110 BPM
    const tempo = 90 + Math.floor(Math.random() * 20);

    return {
      tempo,
      pattern: selected.pattern,
      intensity: selected.intensity,
      steps: selected.steps
    };
  }

  /**
   * Activa la trampa (captura datos)
   */
  captureTrap(trapId: string, incomingData: string): boolean {
    const trap = this.traps.get(trapId);
    if (!trap) return false;

    // Codificar datos entrantes
    const encoded = this.encodeToBase64(incomingData);

    // Marcar como capturado
    trap.captured = true;

    // Verificar secreto 114514
    const hasSecret = this.verifySecret114514(encoded);

    // Actualizar trampa
    trap.encodedData = encoded;
    this.traps.set(trapId, trap);

    return hasSecret;
  }

  /**
   * Verifica presencia del secreto 114514
   */
  private verifySecret114514(data: string): boolean {
    // El secreto puede estar codificado de mГәltiples formas
    const checks = [
      data.includes('MTE0NTE0'), // 114514 base64
      data.includes('114514'),
      this.calculateChecksum(data) === 114514 % 256
    ];
    return checks.some(Boolean);
  }

  private calculateChecksum(data: string): number {
    let sum = 0;
    for (let i = 0; i < data.length; i++) {
      sum += data.charCodeAt(i);
    }
    return sum % 256;
  }

  /**
   * Renderiza patrГіn cumbia visual
   */
  renderCumbiaVisual(rhythm: CumbiaRhythm): string {
    const intensityChar = {
      'LOW': 'в–‘',
      'MEDIUM': 'в–’',
      'HIGH': 'в–“',
      'FIESTA': 'в–Ҳ'
    };

    return `
в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—
в•‘     CUMBIA CONTRAPTION / еқҺжҜ”дәҡйҷ·йҳұ     в•‘
в• в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•Ј
в•‘  Tempo: ${rhythm.tempo} BPM                           в•‘
в•‘  Intensity: ${rhythm.intensity.padEnd(15)} ${intensityChar[rhythm.intensity]}       в•‘
в•‘  Steps: ${rhythm.steps.toString().padStart(3)}                          в•‘
в•‘                                        в•‘
в•‘  Pattern: ${rhythm.pattern}                 в•‘
в•‘                                        в•‘
в•‘  вҷӘ вҷ« вҷӘ вҷ« вҷӘ вҷ« вҷӘ вҷ«                       в•‘
в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ
`;
  }

  /**
   * Obtiene datos del servidor (simulado)
   */
  async fetchFromServer(endpoint: string): Promise<string> {
    // SimulaciГіn de llamada Rust/Server
    await this.simulateNetworkDelay();

    const response = {
      status: 'ok',
      data: this.encodeToBase64(`Server response from ${endpoint}`),
      secretMatched: this.SECRET_ID
    };

    return JSON.stringify(response);
  }

  private simulateNetworkDelay(): Promise<void> {
    return new Promise(resolve => setTimeout(resolve, 50));
  }

  /**
   * Exporta configuraciГіn del sistema
   */
  exportConfig(): string {
    return JSON.stringify({
      secretId: this.SECRET_ID,
      serverBase: this.serverBaseUrl,
      trapCount: this.traps.size,
      encoding: 'base64',
      rhythm: 'cumbia',
      version: '1.0.0'
    }, null, 2);
  }

  /**
   * Lista todas las trampas
   */
  listTraps(): TrapPattern[] {
    return Array.from(this.traps.values());
  }

  /**
   * Limpia trampas capturadas
   */
  clearCaptured(): number {
    let cleared = 0;
    this.traps.forEach((trap, id) => {
      if (trap.captured) {
        this.traps.delete(id);
        cleared++;
      }
    });
    return cleared;
  }

  dispose(): void {
    this.traps.clear();
  }
}

// Singleton instance
export const trapSystem = new SoWeGetTrapSystem();
