  decodeEntities(input: string): string {
    let decoded = input;

    // Replace all known entities
    for (const [entity, char] of Object.entries(this.HTML_ENTITIES)) {
      decoded = decoded.replace(new RegExp(entity.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'g'), char);
