    const yoPatterns = ['Yo', 'yo', 'YO', 'yO'];
    const detected = yoPatterns.some(pattern => 
      input.includes(pattern)
    );

    if (detected) {
      const pattern = this.createHiddenLink();
      pattern.yoDetected = true;
      const reconstructed = this.decodePattern(pattern);

      return {
        detected: true,
        pattern,
        reconstructed
      };
    }

    return {
      detected: false,
      pattern: null,
      reconstructed: ''
    };
  }

