   * Shows the "pattern" without revealing string
   */
  renderPatternVisualization(pattern: LinkPattern): string {
    const matrix = pattern.patternMatrix;
    const lines = [
      'в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—',
      'в•‘  PATTERN LINK VISUALIZATION      в•‘',
      'в• в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•Ј',
      `в•‘  ID: ${pattern.id.slice(0, 20).padEnd(20)} в•‘`,
      'в• в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•Ј',
      ...matrix.map(row => 
        `в•‘  ${row.map(n => n.toString(16).padStart(2, '0')).join(' ')} в•‘`
      ),
      'в• в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•Ј',
      `в•‘  Segments: ${pattern.encodedSegments.length.toString().padStart(2)}            в•‘`,
      `в•‘  Yo Detected: ${pattern.yoDetected ? 'YES' : 'NO '}          в•‘`,
      'в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ'
    ];

    return lines.join('\n');
  }

  /**
   * Verify pattern integrity
   */
  verifyPattern(pattern: LinkPattern): boolean {
    const decoded = this.decodePattern(pattern);
    return decoded === pattern.reconstructedUrl;
